// File hash
const fs = require('fs');

function hashFile(filename) {
    return new Promise((resolve, reject) => {
        const hash = crypto.createHash('sha256');
        const stream = fs.createReadStream(filename);

        stream.on('data', (data) => hash.update(data));
        stream.on('end', () => resolve(hash.digest('hex')));
        stream.on('error', reject);
    });
}

// HMAC
const secret = 'my-secret-key';
const message = 'Important message';

const hmac = crypto.createHmac('sha256', secret)
    .update(message)
    .digest('hex');

// Verify HMAC
function verifyHmac(message, receivedHmac, secret) {
    const calculatedHmac = crypto.createHmac('sha256', secret)
        .update(message)
        .digest('hex');

    return crypto.timingSafeEqual(
        Buffer.from(receivedHmac),
        Buffer.from(calculatedHmac)
    );
}

// RSA digital signature
const crypto = require('crypto');

// Key pair oluştur
const { publicKey, privateKey } = crypto.generateKeyPairSync('rsa', {
    modulusLength: 2048,
    publicKeyEncoding: {
        type: 'spki',
        format: 'pem'
    },
    privateKeyEncoding: {
        type: 'pkcs8',
        format: 'pem'
    }
});

// İmzala
const data = 'Important document';
const sign = crypto.createSign('SHA256');
sign.update(data);
sign.end();
const signature = sign.sign(privateKey, 'hex');

// Doğrula
const verify = crypto.createVerify('SHA256');
verify.update(data);
verify.end();
const isValid = verify.verify(publicKey, signature, 'hex');

console.log('Signature valid:', isValid);

// ECDSA (Elliptic Curve)
const { publicKey: ecPublic, privateKey: ecPrivate } = 
    crypto.generateKeyPairSync('ec', {
        namedCurve: 'secp256k1'  // Bitcoin curve
    });

const ecSign = crypto.createSign('SHA256');
ecSign.update(data);
const ecSignature = ecSign.sign(ecPrivate);

const ecVerify = crypto.createVerify('SHA256');
ecVerify.update(data);
const ecValid = ecVerify.verify(ecPublic, ecSignature);

console.log('EC signature valid:', ecValid);
